choose.when:
INSERT INTO work_classification (
								 task_classification_id
								 , company_id
								 , work_name
								 , default_yn
								 , using_yn
								 )
VALUES (
		SET_DAY_SEQ.NEXTVAL
		, #{vo.companyId}
		, #{vo.workName}
		, #{vo.defaultYn}
		, #{vo.usingYn}
	   )

choose.otherwise:
INSERT INTO task_priority (
							task_priority_id
							, company_id
							, priority_name
							, default_yn
							, using_yn
						   )
VALUES (
		SET_DAY_SEQ.NEXTVAL
		, #{vo.companyId}
		, #{vo.priorityName}
		, #{vo.defaultYn}
		, #{vo.usingYn}
	   )

choose.when:
UPDATE work_classification
SET work_name = #{workName},
    default_yn = #{defaultYn},
    using_yn = #{usingYn}
WHERE task_classification_id = #{taskClassificationId}

choose.otherwise:
UPDATE task_priority
SET priority_name = #{priorityName},
    default_yn = #{defaultYn},
    using_yn = #{usingYn}
WHERE task_priority_id = #{taskPriorityId}
